1. mcp__supabase__apply_migration name='007_rpc_increment_counts'
2. SQL:
  CREATE OR REPLACE FUNCTION public.increment_inquiry_count(p_circle_id uuid)
  RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public
  AS $func$
  DECLARE v_user_id uuid := auth.uid();
  BEGIN
    IF v_user_id IS NULL THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = '42501'; END IF;
    IF NOT EXISTS (SELECT 1 FROM public.circles WHERE id = p_circle_id AND status = 'approved') THEN RETURN; END IF;
    INSERT INTO public.inquiry_events (user_id, circle_id, day) VALUES (v_user_id, p_circle_id, CURRENT_DATE) ON CONFLICT (user_id, circle_id, day) DO NOTHING;
    IF FOUND THEN UPDATE public.circles SET inquiry_count = inquiry_count + 1 WHERE id = p_circle_id; END IF;
  END;
  $func$;
  REVOKE ALL ON FUNCTION public.increment_inquiry_count(uuid) FROM PUBLIC;
  GRANT EXECUTE ON FUNCTION public.increment_inquiry_count(uuid) TO authenticated;
  COMMENT ON FUNCTION public.increment_inquiry_count(uuid) IS 'T-007 F012 채널 모달 클릭 디바운스 카운트 (M-NEW-2)';
  -- increment_view_count
  CREATE OR REPLACE FUNCTION public.increment_view_count(p_circle_id uuid)
  RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public
  AS $func$
  BEGIN
    UPDATE public.circles SET view_count = view_count + 1 WHERE id = p_circle_id AND status = 'approved';
  END;
  $func$;
  REVOKE ALL ON FUNCTION public.increment_view_count(uuid) FROM PUBLIC;
  GRANT EXECUTE ON FUNCTION public.increment_view_count(uuid) TO anon, authenticated;
  COMMENT ON FUNCTION public.increment_view_count(uuid) IS 'T-007 서클 상세 진입 view_count +1 (T-009 세션 디바운스)';
3. 검증: pg_proc 에서 prosecdef=true 두 함수, information_schema.routine_privileges 에서 EXECUTE grantee 확인
